<?php
require_once __DIR__ . '/BaseController.php'; require_once __DIR__ . '/../models/FinancialReport.php';
class ReportController extends BaseController { public function index(): void { $this->requireLogin();$outlet=$_SESSION['kode_outlet'];$nama_outlet=$_SESSION['nama_outlet']??'Outlet DFC';$model=new FinancialReport();if(isset($_POST['simpan_laporan'])){$model->save($outlet,$_POST['tanggal']??date('Y-m-d'),(float)($_POST['omzet_kotor']??0),(float)($_POST['pengeluaran']??0),$_POST['catatan']??'');$this->redirect('laporan.php');}$reports=$model->latest($outlet);$chart=$model->chart($outlet);$labels=array_map(fn($row)=>date('d M',strtotime($row['tanggal'])),$chart);$data_omzet=array_column($chart,'omzet_bersih');$this->view('report',compact('outlet','nama_outlet','reports','labels','data_omzet')); } }
